29	    PLAY_SHOW_SCATTER_TO_MAGIC_POT_ANIMATION: "FLY_PLAY_SHOW_SCATTER_TO_MAGIC_POT_ANIMATION",
30	
31	    /**@ch
32	     * 播放收集 Cash 到 Collect 的動畫
33	     * @param (必填) cashNode 收集 Cash 的節點
34	     * @param (必填) startWorldPosition 起始位置
35	     * @param (必填) endWorldPosition 結束位置
36	     * @param (選填) callback 完成後回調
37	     */
38	    PLAY_FLY_TO_COLLECT_ANIMATION: "FLY_PLAY_FLY_TO_COLLECT_ANIMATION",
39	    
40	    /**@ch
41	     * 播放投入 Cash 的 Spine 演出
42	     * @param (必填) countPerRound 每列投入的 spine 數量
43	     * @param (必填) 要投入哪幾列
44	     * @param (選填) intervalSeconds 間隔幾秒
45	     * @param (選填) callback 完成後回調
46	     */
47	    PLAY_ADD_CASH_ANIMATION: "FLY_PLAY_ADD_CASH_ANIMATION",
48	
