52	     * 之後被晚到 callback 把 col 改回 CashAndBlank。
53	     */
54	    CANCEL_ADD_CASH_ANIMATION: "FLY_CANCEL_ADD_CASH_ANIMATION",
55	}
56	
57	@ccclass('FlyManager')
58	export class FlyManager extends Component {
59	    //#region 屬性
60	    @property( {
61	        type: Prefab,
62	        tooltip: "收集 Cash 到 Collect 的 Prefab"        
63	    })
64	    m_flyToCollectPrefab: Prefab = null;
65	
66	    @property( {
67	        type: Node,
68	        tooltip: "收集 Cash 到 Collect 的節點"
69	    } )
70	    m_collectNodePrefab: Prefab = null;
71	
72	    @property( {
73	        type: Prefab,
74	        tooltip: "投入 Cash 的 Spine Prefab（可同時播放多個）"
75	    } )
76	    m_addCashSpinePrefab: Prefab = null;
77	
78	    @property( {
79	        type: Prefab,
80	        tooltip: "Scatter to MagicPot 的 Prefab"
81	    } )
82	    m_scatterToMagicPotPrefab: Prefab = null;
83	
84	    @property({
85	        type: [Node],
86	        tooltip: "投入的位子"
87	    })
88	    m_addCashPositions: Node[] = [];
89	
90	    @property({
91	        type: [Node],
92	        tooltip: "投入後要移動到的位子"
93	    })
94	    m_addCashTargetPositions: Node[] = [];
95	    
96	    @property({
97	        type: [Node],
98	        tooltip: "遮罩父節點"
99	    })
100	    m_maskParent: Node[] = [];
101	    //#endregion 屬性
102	
103	    //#region 變數
104	    // (已移除未使用的 COLLECT_TRAIL_POOL_SIZE)
105	
106	    /**
107	     * @ch 收集 Cash 到 Collect 的 Prefab Pool 預先建立數量
108	     */
109	    private static readonly FLY_TO_COLLECT_POOL_SIZE: number = 5;
110	
111	    /**
112	     * @ch 投入 Cash Spine 的 Pool 鍵值
113	     */
114	    private static readonly ADD_CASH_POOL_KEY: string = "AddCash";
115	
116	    /**
117	     * @ch 投入 Cash Spine Pool 預先建立數量
118	     */
119	    private static readonly ADD_CASH_POOL_SIZE: number = 25;
120	
121	    /**
122	     * @ch 投入 Cash 動畫名稱（與 ShowAddCash 一致）
123	     */
124	    private static readonly ADD_CASH_ANIMATION_NAME: string = "Trail";
125	
126	    /**
127	     * @ch 投入 Cash 動畫時長（用於回收節點，可依實際動畫調整）
128	     */
129	    private static readonly ADD_CASH_ANIMATION_DURATION: number = 0.6;
130	
131	    /**
132	     * @ch 投入 Cash 從投入位子移動到 target 位子的時長（秒）
133	     */
134	    private static readonly ADD_CASH_MOVE_TO_TARGET_DURATION: number = 0.25;
135	
136	    /**
137	     * @ch Scatter to MagicPot 的 Pool 預先建立數量
138	     */
139	    private static readonly SCATTER_TO_MAGIC_POT_POOL_SIZE: number = 2;
140	
141	    /**
142	     * @ch Scatter to MagicPot 的 Pool 鍵值
143	     */
144	    private static readonly SCATTER_TO_MAGIC_POT_POOL_KEY: string = "ScatterToMagicPot";
145	
146	    /**
147	     * @ch 需要註冊的事件列表
148	     */
149	    private static readonly EVENTS_TO_REGISTER = [
150	        FLY_EVENT.PLAY_FLY_TO_COLLECT_ANIMATION,
151	        FLY_EVENT.PLAY_ADD_CASH_ANIMATION,
152	        FLY_EVENT.PLAY_SHOW_SCATTER_TO_MAGIC_POT_ANIMATION,
153	        FLY_EVENT.CANCEL_ADD_CASH_ANIMATION,
154	    ];
155	
156	    /**
157	     * @ch 是否註冊事件
158	     */
159	    private m_isEventRegistered: boolean = false;
160	
161	    /**@ch PlayAddCashAnimation 取消令牌，每次呼叫遞增，舊的排程檢測到不一致時提前退出 */
162	    private m_addCashCancelId: number = 0;
163	    //#endregion 變數
164	
165	    //#region 方法
166	    onLoad() {
167	        this.RegisterEvent();
168	
169	        if ( this.m_flyToCollectPrefab )
170	        {
171	            PrefabPoolManager.GetInstance().RegisterPrefab( CashType.Cash.toString(), this.m_flyToCollectPrefab, FlyManager.FLY_TO_COLLECT_POOL_SIZE );
172	        }
173	        if ( this.m_addCashSpinePrefab )
174	        {
175	            PrefabPoolManager.GetInstance().RegisterPrefab( FlyManager.ADD_CASH_POOL_KEY, this.m_addCashSpinePrefab, FlyManager.ADD_CASH_POOL_SIZE );
176	        }
177	        if ( this.m_scatterToMagicPotPrefab )
178	        {
179	            PrefabPoolManager.GetInstance().RegisterPrefab( FlyManager.SCATTER_TO_MAGIC_POT_POOL_KEY, this.m_scatterToMagicPotPrefab, FlyManager.SCATTER_TO_MAGIC_POT_POOL_SIZE );
180	        }
181	
182	        this.RegisterTestKeyCodes();
183	    }
184	
185	    onDestroy() {
186	        this.UnregisterEvent();
187	        this.UnregisterTestKeyCodes();
188	    }
189	
190	    /**
191	     * @ch 註冊事件
192	     */
193	    private RegisterEvent() {
194	        if (this.m_isEventRegistered) return;
195	
196	        FlyManager.EVENTS_TO_REGISTER.forEach(eventName => {
197	            eventManager.Register(eventName, this);
198	        });
199	
200	        this.m_isEventRegistered = true;
201	    }
202	
203	    /**
204	     * @ch 取消註冊事件
205	     */
206	    private UnregisterEvent() {
207	        if (!this.m_isEventRegistered) return;
208	
209	        FlyManager.EVENTS_TO_REGISTER.forEach(eventName => {
210	            eventManager.UnRegister(eventName, this);
211	        });
212	
213	        this.m_isEventRegistered = false;
214	    }
215	
216	    /**
217	     * @ch 事件處理
218	     * @param event 事件名稱
219	     * @param args 參數
220	     */
221	    OnEvent(event: string, ...args: any[]) {
222	        switch (event) {
223	            case FLY_EVENT.PLAY_FLY_TO_COLLECT_ANIMATION:
224	                this.PlayFlyToCollectAnimation(args[0], args[1], args[2], args[3], args[4]);
225	                break;
226	
227	            case FLY_EVENT.PLAY_ADD_CASH_ANIMATION:
228	                this.PlayAddCashAnimation(args[0], args[1], args[2], args[3]);
229	                break;
230	
231	            case FLY_EVENT.PLAY_SHOW_SCATTER_TO_MAGIC_POT_ANIMATION:
232	                this.PlayShowScatterToMagicPotAnimation(args[0], args[1], args[2]);
233	                break;
234	
235	            case FLY_EVENT.CANCEL_ADD_CASH_ANIMATION:
236	                // bump cancelId 讓所有尚未 fire 的 MoveTo callback 在 SetReelSymbolMode 之前提前退出
237	                ++this.m_addCashCancelId;
238	                break;
239	        }
240	    }
241	
242	    private async PlayFlyToCollectAnimation(
243	        _cashNode: Node,
244	        startWorldPosition: Vec3,
245	        endWorldPosition: Vec3,
246	        isLong: boolean = true,
247	        callback?: () => void
248	    ): Promise<void>
249	    {
250	        try
251	        {
252	            const effectNode = PrefabPoolManager.GetInstance().GetNode( CashType.Cash.toString(), this.node);
253	            if ( !effectNode )
254	            {
255	                log( "[FlyManager] PlayFlyToCollectAnimation 失敗: 無法建立飛行效果節點" );
256	                callback?.();
257	                return;
258	            }
259	
260	            const flySpine = effectNode.getComponent( BaseSpine );
261	            if ( !flySpine )
262	            {
263	                log( "[FlyManager] PlayFlyToCollectAnimation 失敗: 無法取得 BaseSpine 元件" );
264	                PrefabPoolManager.GetInstance().ReturnNode( CashType.Cash.toString(), effectNode );
265	                callback?.();
266	                return;
267	            }
268	
269	            flySpine.SetNodeActivity( true );
270	            const dirSuffix = endWorldPosition.x <= startWorldPosition.x ? "_L" : "_R";
271	            const startBoneName = isLong ? `Long_Start_Control${dirSuffix}` : `Short_Start_Control${dirSuffix}`;
272	            const endBoneName = isLong ? `Long_End_Control${dirSuffix}` : `Short_End_Control${dirSuffix}`;
273	            const startBone = flySpine.Spine.findBone( startBoneName );
274	            const endBone = flySpine.Spine.findBone( endBoneName );
275	            if ( !startBone || !endBone )
276	            {
277	                log( `[FlyManager] PlayFlyToCollectAnimation 失敗: 無法找到 Spine Bone(${startBoneName}/${endBoneName})` );
278	                flySpine.SetNodeActivity( false );
279	                PrefabPoolManager.GetInstance().ReturnNode( CashType.Cash.toString(), effectNode );
280	                callback?.();
281	                return;
282	            }
283	
284	            // Spine bone 的座標系以 sp.Skeleton 所在節點為基準。
285	            // 若用 flySpine.node（外層節點）去換算，遇到父節點 scale 變動時容易偏移（飛過頭）。
286	            const spineNode = flySpine.Spine?.node ?? flySpine.node;
287	            const startLocalPos = getNodeSpaceAR( spineNode, startWorldPosition );
288	            const endLocalPos = getNodeSpaceAR( spineNode, endWorldPosition );
289	
290	            const controller = effectNode.getComponent( FlyToCollectController );
291	           
292	
293	            // 播放動畫並套用骨頭位置（參照 PlayCollectTrailEffect）
294	            const animName = isLong ? `Long_Trail_Up${dirSuffix}` : `Short_Trail_Up${dirSuffix}`;
295	            const spineAnim = flySpine.Spine.findAnimation( animName );
296	            const animDuration = spineAnim?.duration ?? 1;
297	        
298	            flySpine.PlayAnimation( animName );
299	            startBone.x = startLocalPos.x;
300	            startBone.y = startLocalPos.y;
301	            endBone.x = endLocalPos.x;
302	            endBone.y = endLocalPos.y;
303	
304	            controller?.PlayCollectAnimation( endWorldPosition );
305	
306	            await Define.Wait( this, animDuration - 0.4);
307	            callback?.();
308	
309	            await Define.Wait( this, 0.4);
310	            if (effectNode?.isValid) {
311	                PrefabPoolManager.GetInstance().ReturnNode(CashType.Cash.toString(), effectNode);
312	            }
313	        }
314	        catch ( error )
315	        {
316	            log( "[FlyManager] PlayFlyToCollectAnimation error:", error );
317	            callback?.();
318	        }
319	    }
320	
321	    /**
322	     * @ch 播放投入 Cash 的 Spine 演出
323	     * @param countPerRound 每列投入的 spine 數量（每列都一樣）
324	     * @param columnsToDrop 要投入的列索引，例如 [0,1,2,3] 或 [1,2,3,4,5]；會依索引從 m_addCashPositions 取對應的 pos
325	     * @param intervalSeconds 每個 spine 之間間隔幾秒
326	     * @param callback 可選：全部演出結束後回調
327	     */
328	    private async PlayAddCashAnimation(
329	        countPerRound: number,
330	        columnsToDrop: number[],
331	        intervalSeconds: number,
332	        callback?: () => void
333	    ): Promise<void> {
334	        if ( !this.m_addCashSpinePrefab )
335	        {
336	            log( "[FlyManager] PlayAddCashAnimation 失敗: 未設定 m_addCashSpinePrefab" );
337	            callback?.();
338	            return;
339	        }
340	        if ( !this.m_addCashPositions || this.m_addCashPositions.length === 0 )
341	        {
342	            log( "[FlyManager] PlayAddCashAnimation 失敗: m_addCashPositions 為空" );
343	            callback?.();
344	            return;
345	        }
346	
347	        const count = Math.max( 0, countPerRound );
348	        const playList: number[] = [];
349	        for ( let r = 0; r < columnsToDrop.length; r++ )
350	        {
351	            const col = columnsToDrop[r];
352	            if ( col < 0 || col >= this.m_addCashPositions.length || !this.m_addCashPositions[col]?.isValid )
353	            {
354	                continue;
355	            }
356	            for ( let k = 0; k < count; k++ )
357	            {
358	                playList.push( col );
359	            }
360	        }
361	        if ( playList.length === 0 )
362	        {
363	            callback?.();
364	            return;
365	        }
366	
367	        // 取消令牌：若有新一輪呼叫，舊的排程會提前退出
368	        const cancelId = ++this.m_addCashCancelId;
369	
370	        const effectPlate = Common.m_gameView?.EffectPlate;
371	        eventManager.Dispatch( BLACK_MASK_EVENT.SHOW_BLACK_MASK_60 );
372	        let blackMaskNode: Node = null;
373	        eventManager.Dispatch( BLACK_MASK_EVENT.GET_BLACK_MASK, ( node: Node ) => {
374	            blackMaskNode = node;
375	        } );
376	        const parent = this.node;
377	        const poolKey = FlyManager.ADD_CASH_POOL_KEY;
378	        const animName = FlyManager.ADD_CASH_ANIMATION_NAME;
379	        const animDuration = FlyManager.ADD_CASH_ANIMATION_DURATION;
380	        // 記錄每列最後一個符號在 playList 中的索引，用來判斷何時關框
381	        const lastIndexPerCol = new Map<number, number>();
382	        for ( let i = 0; i < playList.length; i++ )
383	        {
384	            lastIndexPerCol.set( playList[i], i );
385	        }
386	        // 每列的 PushNode 資料，關框時一起 PopNode
387	        const colFrameDataMap = new Map<number, PopupNodeData | null>();
388	        let magicPotNode: Node = null;
389	
390	        eventManager.Dispatch(MAGIC_POT_EVENT.GET_NODE, (node: Node) => {
391	            if (node) {
392	                magicPotNode = node;
393	            }
394	        });
395	
396	        // 預先快取每列的世界座標和局部座標（避免迴圈中重複計算）
397	        const cachedPos = new Map<number, Vec3>();
398	        const cachedMagicPotPos = magicPotNode ? getNodeSpaceAR( parent, magicPotNode.getWorldPosition() ) : null;
399	        for ( const col of lastIndexPerCol.keys() )
400	        {
401	            const positionNode = this.m_addCashPositions[col];
402	            if ( positionNode?.isValid )
403	            {
404	                cachedPos.set( col, getNodeSpaceAR( parent, positionNode.getWorldPosition() ) );
405	            }
406	        }
407	
408	        // 播放投入 Cash 音效
409	        const addCashAudioId = AudioManager.Play(AudioManager.AudioClips.AddCash);
410	
411	        for ( let i = 0; i < playList.length; i++ )
412	        {
413	            const col = playList[i];
414	            const delayStart = i * intervalSeconds;
415	
416	            Define.Wait( this, delayStart ).then( () => {
417	                if ( !this.node?.isValid || this.m_addCashCancelId !== cancelId ) return;
418	                if ( effectPlate )
419	                {
420	                    // 每列只在第一次出現時開框，後續同列符號不重複開關
421	                    if ( !colFrameDataMap.has( col ) )
422	                    {
423	                        let fData: PopupNodeData | null = null;
424	                        // 開框前將投入框節點掛至黑張底下，確保層級正確
425	                        if ( blackMaskNode && blackMaskNode.isValid )
426	                        {
427	                            const frameNode = effectPlate.GetFreeGameAddCashFrameNode( col );
428	                            if ( frameNode && frameNode.isValid )
429	                            {
430	                                fData = Common.PushNode( frameNode, blackMaskNode );
431	                            }
432	                        }
433	                        colFrameDataMap.set( col, fData );
434	                        effectPlate.SetFreeGameAddCashFrameShow( col, true );
435	                    }
436	                }
437	                const effectNode = PrefabPoolManager.GetInstance().GetNode( poolKey, parent );
438	                if ( !effectNode )
439	                {
440	                    log( "[FlyManager] PlayAddCashAnimation 無法取得 AddCash 節點" );
441	                    return;
442	                }
443	                const flySpine = effectNode.getComponent( BaseSpine );
444	                if ( !flySpine || !flySpine.Spine )
445	                {
446	                    log( "[FlyManager] PlayAddCashAnimation 無法取得 BaseSpine 元件，回收節點" );
447	                    PrefabPoolManager.GetInstance().ReturnNode( poolKey, effectNode );
448	                    return;
449	                }
450	                flySpine.Spine.enabled = true;
451	                const symbolNode = this.FindChildByName( effectNode, "Symbol" );
452	                if ( symbolNode && symbolNode.isValid )
453	                {
454	                    symbolNode.setPosition( 0, 0, 0 );
455	                }
456	                const pos = cachedPos.get( col );
457	                effectNode.setPosition( 0, 0, 0 );
458	                effectNode.active = true;
459	                const showAddCash = effectNode.getComponent( ShowAddCash );
460	                if ( showAddCash )
461	                {
462	                    showAddCash.ShowAddCash();
463	                }
464	                const startBone = flySpine?.Spine?.findBone( 'Start_Control' );
465	                const endBone = flySpine?.Spine?.findBone( 'End_Control' );
466	
467	                flySpine.PlayAnimation( animName );
468	                if ( startBone && cachedMagicPotPos ) { startBone.x = cachedMagicPotPos.x; startBone.y = cachedMagicPotPos.y; }
469	                if ( endBone && pos ) { endBone.x = pos.x; endBone.y = pos.y; }
470	
471	                Define.Wait( this, animDuration ).then( () => {
472	                    if ( !this.node?.isValid || !effectNode?.isValid || this.m_addCashCancelId !== cancelId ) {
473	                        if ( effectNode?.isValid ) PrefabPoolManager.GetInstance().ReturnNode( poolKey, effectNode );
474	                        return;
475	                    }
476	                    const positionNode = this.m_addCashPositions[col];
477	                    const dropWorldPos = positionNode.getWorldPosition();
478	                    if ( flySpine && flySpine.Spine )
479	                    {
480	                        flySpine.Spine.enabled = false;
481	                    }
482	                    const symbolNodeForMove = this.FindChildByName( effectNode, "Symbol" );
483	                    if ( symbolNodeForMove && symbolNodeForMove.isValid )
484	                    {
485	                        symbolNodeForMove.setPosition( 0, 0, 0 );
486	                    }
487	                    // cash index 1,2,3,4 → mask index 1；index 5 → mask index 3；其它照 col
488	                    const maskIndex = col === 5 ? 2 : ( col >= 1 && col <= 4 ? 1 : col );
489	                    const maskParent = ( this.m_maskParent && this.m_maskParent.length > 0 )
490	                        ? ( this.m_maskParent[ maskIndex ] ?? this.m_maskParent[ 0 ] )
491	                        : null;
492	                    if ( maskParent && maskParent.isValid )
493	                    {
494	                        effectNode.removeFromParent();
495	                        maskParent.addChild( effectNode );
496	                        effectNode.setSiblingIndex( maskParent.children.length - 1 );
497	                        if ( !maskParent.active )
498	                        {
499	                            log( "[FlyManager] PlayAddCashAnimation 遮罩父節點未啟用，物件可能不可見" );
500	                        }
501	                    }
502	                    effectNode.setWorldPosition( dropWorldPos );
503	                    effectNode.active = true;
504	                    const targetNode = this.m_addCashTargetPositions?.[ col ] ?? this.m_addCashTargetPositions?.[ 0 ];
505	                    if ( targetNode && targetNode.isValid )
506	                    {
507	                        const targetWorldPos = targetNode.getWorldPosition();
508	
509	                        const uiOpacity = effectNode.getComponent( UIOpacity ) || effectNode.addComponent( UIOpacity );
510	                        uiOpacity.opacity = 255;
511	                        Tween.stopAllByTarget( uiOpacity );
512	                        const fadeDelay = FlyManager.ADD_CASH_MOVE_TO_TARGET_DURATION ;
513	                        const fadeDuration = FlyManager.ADD_CASH_MOVE_TO_TARGET_DURATION - fadeDelay;
514	                        tween( uiOpacity )
515	                            .delay( fadeDelay )
516	                            .to( Math.max( 0, fadeDuration ), { opacity: 0 } )
517	                            .start();
518	
519	                        Common.MoveTo(
520	                            effectNode,
521	                            dropWorldPos,
522	                            targetWorldPos,
523	                            FlyManager.ADD_CASH_MOVE_TO_TARGET_DURATION,
524	                            () => {
525	                                // 回收前重置透明度，避免下次取出是透明的
526	                                Tween.stopAllByTarget( uiOpacity );
527	                                uiOpacity.opacity = 255;
528	                                PrefabPoolManager.GetInstance().ReturnNode( poolKey, effectNode );
529	                                // cancelId 不符 → 演出已被取消（例：EnterFreeState 演出結束時 dispatch CANCEL_ADD_CASH_ANIMATION）
530	                                //   跳過 SetReelSymbolMode 與框關閉邏輯，避免污染下游 SetAllReelSymbolMode(Normal) 設定
531	                                if ( !this.node?.isValid || this.m_addCashCancelId !== cancelId ) return;
532	                                this.SetReelSymbolMode( col, ReelSymbolMode.CashAndBlank );
533	                                // 此列最後一個符號落底時才關閉投入框
534	                                if ( i === lastIndexPerCol.get( col ) && effectPlate )
535	                                {
536	                                    effectPlate.SetFreeGameAddCashFrameShow( col, false );
537	                                    const fData = colFrameDataMap.get( col );
538	                                    if ( fData ) { Common.PopNode( fData ); }
539	                                    colFrameDataMap.delete( col );
540	                                }
541	                            }
542	                        );
543	                    }
544	                    else
545	                    {
546	                        // 沒有 targetNode 也要確保回收前是正常透明度
547	                        const uiOpacity = effectNode.getComponent( UIOpacity );
548	                        if ( uiOpacity )
549	                        {
550	                            Tween.stopAllByTarget( uiOpacity );
551	                            uiOpacity.opacity = 255;
552	                        }
553	                        PrefabPoolManager.GetInstance().ReturnNode( poolKey, effectNode );
554	                    }
555	                } );
556	            } );
557	        }
558	
559	        const totalDuration = ( playList.length - 1 ) * intervalSeconds + animDuration + FlyManager.ADD_CASH_MOVE_TO_TARGET_DURATION;
560	        await Define.Wait( this, totalDuration );
561	        // 安全清理：正常情況下框已在 MoveTo callback 中關閉；此處處理異常殘留
562	        for ( const [ remainCol, fData ] of colFrameDataMap )
563	        {
564	            if ( effectPlate ) { effectPlate.SetFreeGameAddCashFrameShow( remainCol, false ); }
565	            if ( fData ) { Common.PopNode( fData ); }
566	        }
567	        colFrameDataMap.clear();
568	        eventManager.Dispatch( BLACK_MASK_EVENT.HIDE_BLACK_MASK );
569	
570	        try { callback?.(); } catch ( e ) { log( "[FlyManager] PlayAddCashAnimation callback error:", e ); }
571	    }
572	
573	    /**
574	     * @ch 在節點底下依名稱尋找子節點（含孫節點）
575	     */
576	    private FindChildByName(root: Node, name: string): Node | null {
577	        if (!root || !root.isValid) return null;
578	        if (root.name === name) return root;
579	        for (let i = 0; i < root.children.length; i++) {
580	            const found = this.FindChildByName(root.children[i], name);
581	            if (found) return found;
582	        }
583	        return null;
584	    }
585	
586	    /**
587	     * @ch 依起始世界座標判斷 Scatter→魔法罐 是否使用長軌（前三輪 Long，後三輪 Short）
588	     * @param startWorldPosition 起始世界座標
589	     * @returns 第 0–2 輪為 true（Long_Trail），第 3–5 輪為 false；無法對應盤面時預設 true
590	     */
591	    private IsScatterToMagicPotLongTrailByStartWorldPosition( startWorldPosition: Vec3 ): boolean
592	    {
593	        const slotReels = Common.m_gameView?.SlotReels;
594	        if ( !slotReels )
595	        {
596	            return true;
597	        }
598	
599	        let nearestCol = 0;
600	        let smallestDx = Number.POSITIVE_INFINITY;
601	        for ( let col = 0; col < Game_Define.COL; ++col )
602	        {
603	            const refWorldPos = slotReels.GetSymbolInitWorldPositionFromColRow( col, 0 );
604	            const dx = Math.abs( startWorldPosition.x - refWorldPos.x );
605	            if ( dx < smallestDx )
606	            {
607	                smallestDx = dx;
608	                nearestCol = col;
609	            }
610	        }
611	
612	        return nearestCol < 3;
613	    }
614	
615	    /**
616	     * @ch 播放 Scatter 飛向魔法罐的 Trail 效果（結構同 PlayCollectTrailEffect）
617	     * @param startWorldPosition 起始世界座標
618	     * @param endWorldPosition 結束世界座標
619	     * @param callback 完成後回調
620	     */
621	    async PlayShowScatterToMagicPotAnimation(startWorldPosition: Vec3, endWorldPosition: Vec3, callback?: () => void): Promise<void>
622	    {
623	        let effectNode: Node = null;
624	        let scatterSpine: BaseSpine = null;
625	        effectNode = PrefabPoolManager.GetInstance().GetNode( FlyManager.SCATTER_TO_MAGIC_POT_POOL_KEY, this.node );
626	            if ( !effectNode )
627	            {
628	                log( "[FlyManager] PlayShowScatterToMagicPotAnimation 失敗: 無法建立飛行效果節點" );
629	                return;
630	            }
631	            effectNode.setWorldPosition( startWorldPosition );
632	            scatterSpine = effectNode.getComponent( BaseSpine );
633	            if ( !scatterSpine )
634	            {
635	                log( "[FlyManager] PlayShowScatterToMagicPotAnimation 失敗: 無法取得 BaseSpine 元件" );
636	                PrefabPoolManager.GetInstance().ReturnNode( FlyManager.SCATTER_TO_MAGIC_POT_POOL_KEY, effectNode );
637	                callback?.();
638	                return;
639	            }
640	
641	            const isLong = this.IsScatterToMagicPotLongTrailByStartWorldPosition( startWorldPosition );
642	
643	            scatterSpine.SetNodeActivity( true );
644	            const startBoneName = isLong ? "Long_Start_Control" : "Short_Start_Control";
645	            const endBoneName = isLong ? "Long_End_Control" : "Short_End_Control";
646	            const startBone = scatterSpine.Spine.findBone( startBoneName );
647	            const endBone = scatterSpine.Spine.findBone( endBoneName );
648	
649	            if ( !startBone || !endBone )
650	            {
651	                log( `[FlyManager] PlayShowScatterToMagicPotAnimation 失敗: 無法找到 Spine Bone(${startBoneName}/${endBoneName})` );
652	                scatterSpine.SetNodeActivity( false );
653	                PrefabPoolManager.GetInstance().ReturnNode( FlyManager.SCATTER_TO_MAGIC_POT_POOL_KEY, effectNode );
654	                callback?.();
655	                return;
656	            }
657	
658	            const spineNode = scatterSpine.Spine?.node ?? scatterSpine.node;
659	
660	            const startLocalPos = getNodeSpaceAR( spineNode, startWorldPosition );
661	            const endLocalPos = getNodeSpaceAR( spineNode, endWorldPosition );
662	
663	            const animName = isLong ? "Long_Trail_Up" : "Short_Trail_Up";
664	
665	            scatterSpine.PlayAnimation( animName );
666	            endBone.x = endLocalPos.x;
667	            endBone.y = endLocalPos.y;
668	            startBone.x = startLocalPos.x;
669	            startBone.y = startLocalPos.y;
670	
671	            await Define.Wait( this, 0.5 );
672	
673	            scatterSpine.SetNodeActivity( false );
674	            if (effectNode) {
675	                PrefabPoolManager.GetInstance().ReturnNode( FlyManager.SCATTER_TO_MAGIC_POT_POOL_KEY, effectNode );
676	            }
677	
678	            callback?.();
679	    }
