import { _decorator, Component, log, Prefab, Vec3, input, Input, EventKeyboard, KeyCode, Node, tween, Tween, UIOpacity } from 'cc';
import { eventManager } from 'db://astarte-framework/Managers';
import { PrefabPoolManager } from './Common/PrefabPoolManager';
import { BaseSpine } from './Spine/BaseSpine';
import { FlyToCollectController } from './FlyToCollectController';
import { getNodeSpaceAR } from './Common/NodeProperty';
import { Define } from 'db://astarte-framework/utilis';
import { Common, PopupNodeData } from './Common/Common';
import { MAGIC_POT_EVENT } from './MagicPot/MagicPotController';
import { BLACK_MASK_EVENT } from './BlackMaskManager';
import { ShowAddCash } from './Cash/ShowAddCash';
import Game_Define, { ReelSymbolMode } from './Game_Define';
import { AudioManager } from './Audio/AudioManager';
import { DEBUG } from 'cc/env';
const { ccclass, property } = _decorator;

export enum CashType {
    Cash = 4,
    MysteryCash,
}

export const FLY_EVENT = {
    /**@ch
     * 播放 Scatter to MagicPot 的動畫
     * @param (必填) startWorldPosition 起始位置
     * @param (必填) endWorldPosition 結束位置
     * @param (選填) callback 完成後回調
     */
    PLAY_SHOW_SCATTER_TO_MAGIC_POT_ANIMATION: "FLY_PLAY_SHOW_SCATTER_TO_MAGIC_POT_ANIMATION",

    /**@ch
     * 播放收集 Cash 到 Collect 的動畫
     * @param (必填) cashNode 收集 Cash 的節點
     * @param (必填) startWorldPosition 起始位置
     * @param (必填) endWorldPosition 結束位置
     * @param (選填) callback 完成後回調
     */
    PLAY_FLY_TO_COLLECT_ANIMATION: "FLY_PLAY_FLY_TO_COLLECT_ANIMATION",

    /**@ch
     * 播放投入 Cash 的 Spine 演出
     * @param (必填) countPerRound 每列投入的 spine 數量
     * @param (必填) 要投入哪幾列
     * @param (選填) intervalSeconds 間隔幾秒
     * @param (選填) callback 完成後回調
     */
    PLAY_ADD_CASH_ANIMATION: "FLY_PLAY_ADD_CASH_ANIMATION",

    /**@ch
     * 取消當前 AddCash 演出延遲 callback。呼叫此事件後，所有尚未 fire 的 MoveTo callback
     * 都會跳過 SetReelSymbolMode，避免在 EnterFreeState 演出結束、SetAllReelSymbolMode(Normal)
     * 之後被晚到 callback 把 col 改回 CashAndBlank。
     */
    CANCEL_ADD_CASH_ANIMATION: "FLY_CANCEL_ADD_CASH_ANIMATION",
}

@ccclass('FlyManager')
export class FlyManager extends Component {
    //#region 屬性
    @property( {
        type: Prefab,
        tooltip: "收集 Cash 到 Collect 的 Prefab"        
    })
    m_flyToCollectPrefab: Prefab = null;

    @property( {
        type: Node,
        tooltip: "收集 Cash 到 Collect 的節點"
    } )
    m_collectNodePrefab: Prefab = null;

    @property( {
        type: Prefab,
        tooltip: "投入 Cash 的 Spine Prefab（可同時播放多個）"
    } )
    m_addCashSpinePrefab: Prefab = null;

    @property( {
        type: Prefab,
        tooltip: "Scatter to MagicPot 的 Prefab"
    } )
    m_scatterToMagicPotPrefab: Prefab = null;

    @property({
        type: [Node],
        tooltip: "投入的位子"
    })
    m_addCashPositions: Node[] = [];

    @property({
        type: [Node],
        tooltip: "投入後要移動到的位子"
    })
    m_addCashTargetPositions: Node[] = [];

    @property({
        type: [Node],
        tooltip: "遮罩父節點"
    })
    m_maskParent: Node[] = [];
    //#endregion 屬性

    //#region 變數
    // (已移除未使用的 COLLECT_TRAIL_POOL_SIZE)

    /**
     * @ch 收集 Cash 到 Collect 的 Prefab Pool 預先建立數量
     */
    private static readonly FLY_TO_COLLECT_POOL_SIZE: number = 5;

    /**
     * @ch 投入 Cash Spine 的 Pool 鍵值
     */
    private static readonly ADD_CASH_POOL_KEY: string = "AddCash";

    /**
     * @ch 投入 Cash Spine Pool 預先建立數量
     */
    private static readonly ADD_CASH_POOL_SIZE: number = 25;

    /**
     * @ch 投入 Cash 動畫名稱（與 ShowAddCash 一致）
     */
    private static readonly ADD_CASH_ANIMATION_NAME: string = "Trail";

    /**
     * @ch 投入 Cash 動畫時長（用於回收節點，可依實際動畫調整）
     */
    private static readonly ADD_CASH_ANIMATION_DURATION: number = 0.6;

    /**
     * @ch 投入 Cash 從投入位子移動到 target 位子的時長（秒）
     */
    private static readonly ADD_CASH_MOVE_TO_TARGET_DURATION: number = 0.25;

    /**
     * @ch Scatter to MagicPot 的 Pool 預先建立數量
     */
    private static readonly SCATTER_TO_MAGIC_POT_POOL_SIZE: number = 2;

    /**
     * @ch Scatter to MagicPot 的 Pool 鍵值
     */
    private static readonly SCATTER_TO_MAGIC_POT_POOL_KEY: string = "ScatterToMagicPot";

    /**
     * @ch 需要註冊的事件列表
     */
    private static readonly EVENTS_TO_REGISTER = [
        FLY_EVENT.PLAY_FLY_TO_COLLECT_ANIMATION,
        FLY_EVENT.PLAY_ADD_CASH_ANIMATION,
        FLY_EVENT.PLAY_SHOW_SCATTER_TO_MAGIC_POT_ANIMATION,
        FLY_EVENT.CANCEL_ADD_CASH_ANIMATION,
    ];

    /**
     * @ch 是否註冊事件
     */
    private m_isEventRegistered: boolean = false;

    /**@ch PlayAddCashAnimation 取消令牌，每次呼叫遞增，舊的排程檢測到不一致時提前退出 */
    private m_addCashCancelId: number = 0;
    //#endregion 變數

    //#region 方法
    onLoad() {
        this.RegisterEvent();

        if ( this.m_flyToCollectPrefab )
        {
            PrefabPoolManager.GetInstance().RegisterPrefab( CashType.Cash.toString(), this.m_flyToCollectPrefab, FlyManager.FLY_TO_COLLECT_POOL_SIZE );
        }
        if ( this.m_addCashSpinePrefab )
        {
            PrefabPoolManager.GetInstance().RegisterPrefab( FlyManager.ADD_CASH_POOL_KEY, this.m_addCashSpinePrefab, FlyManager.ADD_CASH_POOL_SIZE );
        }
        if ( this.m_scatterToMagicPotPrefab )
        {
            PrefabPoolManager.GetInstance().RegisterPrefab( FlyManager.SCATTER_TO_MAGIC_POT_POOL_KEY, this.m_scatterToMagicPotPrefab, FlyManager.SCATTER_TO_MAGIC_POT_POOL_SIZE );
        }

        this.RegisterTestKeyCodes();
    }

    onDestroy() {
        this.UnregisterEvent();
        this.UnregisterTestKeyCodes();
    }

    /**
     * @ch 註冊事件
     */
    private RegisterEvent() {
        if (this.m_isEventRegistered) return;

        FlyManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.Register(eventName, this);
        });

        this.m_isEventRegistered = true;
    }

    /**
     * @ch 取消註冊事件
     */
    private UnregisterEvent() {
        if (!this.m_isEventRegistered) return;

        FlyManager.EVENTS_TO_REGISTER.forEach(eventName => {
            eventManager.UnRegister(eventName, this);
        });

        this.m_isEventRegistered = false;
    }

    /**
     * @ch 事件處理
     * @param event 事件名稱
     * @param args 參數
     */
    OnEvent(event: string, ...args: any[]) {
        switch (event) {
            case FLY_EVENT.PLAY_FLY_TO_COLLECT_ANIMATION:
                this.PlayFlyToCollectAnimation(args[0], args[1], args[2], args[3], args[4]);
                break;

            case FLY_EVENT.PLAY_ADD_CASH_ANIMATION:
                this.PlayAddCashAnimation(args[0], args[1], args[2], args[3]);
                break;

            case FLY_EVENT.PLAY_SHOW_SCATTER_TO_MAGIC_POT_ANIMATION:
                this.PlayShowScatterToMagicPotAnimation(args[0], args[1], args[2]);
                break;

            case FLY_EVENT.CANCEL_ADD_CASH_ANIMATION:
                // bump cancelId 讓所有尚未 fire 的 MoveTo callback 在 SetReelSymbolMode 之前提前退出
                ++this.m_addCashCancelId;
                break;
        }
    }

    private async PlayFlyToCollectAnimation(
        _cashNode: Node,
        startWorldPosition: Vec3,
        endWorldPosition: Vec3,
        isLong: boolean = true,
        callback?: () => void
    ): Promise<void>
    {
        try
        {
            const effectNode = PrefabPoolManager.GetInstance().GetNode( CashType.Cash.toString(), this.node);
            if ( !effectNode )
            {
                log( "[FlyManager] PlayFlyToCollectAnimation 失敗: 無法建立飛行效果節點" );
                callback?.();
                return;
            }

            const flySpine = effectNode.getComponent( BaseSpine );
            if ( !flySpine )
            {
                log( "[FlyManager] PlayFlyToCollectAnimation 失敗: 無法取得 BaseSpine 元件" );
                PrefabPoolManager.GetInstance().ReturnNode( CashType.Cash.toString(), effectNode );
                callback?.();
                return;
            }

            flySpine.SetNodeActivity( true );
            const dirSuffix = endWorldPosition.x <= startWorldPosition.x ? "_L" : "_R";
            const startBoneName = isLong ? `Long_Start_Control${dirSuffix}` : `Short_Start_Control${dirSuffix}`;
            const endBoneName = isLong ? `Long_End_Control${dirSuffix}` : `Short_End_Control${dirSuffix}`;
            const startBone = flySpine.Spine.findBone( startBoneName );
            const endBone = flySpine.Spine.findBone( endBoneName );
            if ( !startBone || !endBone )
            {
                log( `[FlyManager] PlayFlyToCollectAnimation 失敗: 無法找到 Spine Bone(${startBoneName}/${endBoneName})` );
                flySpine.SetNodeActivity( false );
                PrefabPoolManager.GetInstance().ReturnNode( CashType.Cash.toString(), effectNode );
                callback?.();
                return;
            }

            // Spine bone 的座標系以 sp.Skeleton 所在節點為基準。
            // 若用 flySpine.node（外層節點）去換算，遇到父節點 scale 變動時容易偏移（飛過頭）。
            const spineNode = flySpine.Spine?.node ?? flySpine.node;
            const startLocalPos = getNodeSpaceAR( spineNode, startWorldPosition );
            const endLocalPos = getNodeSpaceAR( spineNode, endWorldPosition );

            const controller = effectNode.getComponent( FlyToCollectController );


            // 播放動畫並套用骨頭位置（參照 PlayCollectTrailEffect）
            const animName = isLong ? `Long_Trail_Up${dirSuffix}` : `Short_Trail_Up${dirSuffix}`;
            const spineAnim = flySpine.Spine.findAnimation( animName );
            const animDuration = spineAnim?.duration ?? 1;

            flySpine.PlayAnimation( animName );
            startBone.x = startLocalPos.x;
            startBone.y = startLocalPos.y;
            endBone.x = endLocalPos.x;
            endBone.y = endLocalPos.y;

            controller?.PlayCollectAnimation( endWorldPosition );

            await Define.Wait( this, animDuration - 0.4);
            callback?.();

            await Define.Wait( this, 0.4);
            if (effectNode?.isValid) {
                PrefabPoolManager.GetInstance().ReturnNode(CashType.Cash.toString(), effectNode);
            }
        }
        catch ( error )
        {
            log( "[FlyManager] PlayFlyToCollectAnimation error:", error );
            callback?.();
        }
    }

    /**
     * @ch 播放投入 Cash 的 Spine 演出
     * @param countPerRound 每列投入的 spine 數量（每列都一樣）
     * @param columnsToDrop 要投入的列索引，例如 [0,1,2,3] 或 [1,2,3,4,5]；會依索引從 m_addCashPositions 取對應的 pos
     * @param intervalSeconds 每個 spine 之間間隔幾秒
     * @param callback 可選：全部演出結束後回調
     */
    private async PlayAddCashAnimation(
        countPerRound: number,
        columnsToDrop: number[],
        intervalSeconds: number,
        callback?: () => void
    ): Promise<void> {
        if ( !this.m_addCashSpinePrefab )
        {
            log( "[FlyManager] PlayAddCashAnimation 失敗: 未設定 m_addCashSpinePrefab" );
            callback?.();
            return;
        }
        if ( !this.m_addCashPositions || this.m_addCashPositions.length === 0 )
        {
            log( "[FlyManager] PlayAddCashAnimation 失敗: m_addCashPositions 為空" );
            callback?.();
            return;
        }

        const count = Math.max( 0, countPerRound );
        const playList: number[] = [];
        for ( let r = 0; r < columnsToDrop.length; r++ )
        {
            const col = columnsToDrop[r];
            if ( col < 0 || col >= this.m_addCashPositions.length || !this.m_addCashPositions[col]?.isValid )
            {
                continue;
            }
            for ( let k = 0; k < count; k++ )
            {
                playList.push( col );
            }
        }
        if ( playList.length === 0 )
        {
            callback?.();
            return;
        }

        // 取消令牌：若有新一輪呼叫，舊的排程會提前退出
        const cancelId = ++this.m_addCashCancelId;

        const effectPlate = Common.m_gameView?.EffectPlate;
        eventManager.Dispatch( BLACK_MASK_EVENT.SHOW_BLACK_MASK_60 );
        let blackMaskNode: Node = null;
        eventManager.Dispatch( BLACK_MASK_EVENT.GET_BLACK_MASK, ( node: Node ) => {
            blackMaskNode = node;
        } );
        const parent = this.node;
        const poolKey = FlyManager.ADD_CASH_POOL_KEY;
        const animName = FlyManager.ADD_CASH_ANIMATION_NAME;
        const animDuration = FlyManager.ADD_CASH_ANIMATION_DURATION;
        // 記錄每列最後一個符號在 playList 中的索引，用來判斷何時關框
        const lastIndexPerCol = new Map<number, number>();
        for ( let i = 0; i < playList.length; i++ )
        {
            lastIndexPerCol.set( playList[i], i );
        }
        // 每列的 PushNode 資料，關框時一起 PopNode
        const colFrameDataMap = new Map<number, PopupNodeData | null>();
        let magicPotNode: Node = null;

        eventManager.Dispatch(MAGIC_POT_EVENT.GET_NODE, (node: Node) => {
            if (node) {
                magicPotNode = node;
            }
        });

        // 預先快取每列的世界座標和局部座標（避免迴圈中重複計算）
        const cachedPos = new Map<number, Vec3>();
        const cachedMagicPotPos = magicPotNode ? getNodeSpaceAR( parent, magicPotNode.getWorldPosition() ) : null;
        for ( const col of lastIndexPerCol.keys() )
        {
            const positionNode = this.m_addCashPositions[col];
            if ( positionNode?.isValid )
            {
                cachedPos.set( col, getNodeSpaceAR( parent, positionNode.getWorldPosition() ) );
            }
        }

        // 播放投入 Cash 音效
        const addCashAudioId = AudioManager.Play(AudioManager.AudioClips.AddCash);

        for ( let i = 0; i < playList.length; i++ )
        {
            const col = playList[i];
            const delayStart = i * intervalSeconds;

            Define.Wait( this, delayStart ).then( () => {
                if ( !this.node?.isValid || this.m_addCashCancelId !== cancelId ) return;
                if ( effectPlate )
                {
                    // 每列只在第一次出現時開框，後續同列符號不重複開關
                    if ( !colFrameDataMap.has( col ) )
                    {
                        let fData: PopupNodeData | null = null;
                        // 開框前將投入框節點掛至黑張底下，確保層級正確
                        if ( blackMaskNode && blackMaskNode.isValid )
                        {
                            const frameNode = effectPlate.GetFreeGameAddCashFrameNode( col );
                            if ( frameNode && frameNode.isValid )
                            {
                                fData = Common.PushNode( frameNode, blackMaskNode );
                            }
                        }
                        colFrameDataMap.set( col, fData );
                        effectPlate.SetFreeGameAddCashFrameShow( col, true );
                    }
                }
                const effectNode = PrefabPoolManager.GetInstance().GetNode( poolKey, parent );
                if ( !effectNode )
                {
                    log( "[FlyManager] PlayAddCashAnimation 無法取得 AddCash 節點" );
                    return;
                }
                const flySpine = effectNode.getComponent( BaseSpine );
                if ( !flySpine || !flySpine.Spine )
                {
                    log( "[FlyManager] PlayAddCashAnimation 無法取得 BaseSpine 元件，回收節點" );
                    PrefabPoolManager.GetInstance().ReturnNode( poolKey, effectNode );
                    return;
                }
                flySpine.Spine.enabled = true;
                const symbolNode = this.FindChildByName( effectNode, "Symbol" );
                if ( symbolNode && symbolNode.isValid )
                {
                    symbolNode.setPosition( 0, 0, 0 );
                }
                const pos = cachedPos.get( col );
                effectNode.setPosition( 0, 0, 0 );
                effectNode.active = true;
                const showAddCash = effectNode.getComponent( ShowAddCash );
                if ( showAddCash )
                {
                    showAddCash.ShowAddCash();
                }
                const startBone = flySpine?.Spine?.findBone( 'Start_Control' );
                const endBone = flySpine?.Spine?.findBone( 'End_Control' );

                flySpine.PlayAnimation( animName );
                if ( startBone && cachedMagicPotPos ) { startBone.x = cachedMagicPotPos.x; startBone.y = cachedMagicPotPos.y; }
                if ( endBone && pos ) { endBone.x = pos.x; endBone.y = pos.y; }

                Define.Wait( this, animDuration ).then( () => {
                    if ( !this.node?.isValid || !effectNode?.isValid || this.m_addCashCancelId !== cancelId ) {
                        if ( effectNode?.isValid ) PrefabPoolManager.GetInstance().ReturnNode( poolKey, effectNode );
                        return;
                    }
                    const positionNode = this.m_addCashPositions[col];
                    const dropWorldPos = positionNode.getWorldPosition();
                    if ( flySpine && flySpine.Spine )
                    {
                        flySpine.Spine.enabled = false;
                    }
                    const symbolNodeForMove = this.FindChildByName( effectNode, "Symbol" );
                    if ( symbolNodeForMove && symbolNodeForMove.isValid )
                    {
                        symbolNodeForMove.setPosition( 0, 0, 0 );
                    }
                    // cash index 1,2,3,4 → mask index 1；index 5 → mask index 3；其它照 col
                    const maskIndex = col === 5 ? 2 : ( col >= 1 && col <= 4 ? 1 : col );
                    const maskParent = ( this.m_maskParent && this.m_maskParent.length > 0 )
                        ? ( this.m_maskParent[ maskIndex ] ?? this.m_maskParent[ 0 ] )
                        : null;
                    if ( maskParent && maskParent.isValid )
                    {
                        effectNode.removeFromParent();
                        maskParent.addChild( effectNode );
                        effectNode.setSiblingIndex( maskParent.children.length - 1 );
                        if ( !maskParent.active )
                        {
                            log( "[FlyManager] PlayAddCashAnimation 遮罩父節點未啟用，物件可能不可見" );
                        }
                    }
                    effectNode.setWorldPosition( dropWorldPos );
                    effectNode.active = true;
                    const targetNode = this.m_addCashTargetPositions?.[ col ] ?? this.m_addCashTargetPositions?.[ 0 ];
                    if ( targetNode && targetNode.isValid )
                    {
                        const targetWorldPos = targetNode.getWorldPosition();

                        const uiOpacity = effectNode.getComponent( UIOpacity ) || effectNode.addComponent( UIOpacity );
                        uiOpacity.opacity = 255;
                        Tween.stopAllByTarget( uiOpacity );
                        const fadeDelay = FlyManager.ADD_CASH_MOVE_TO_TARGET_DURATION ;
                        const fadeDuration = FlyManager.ADD_CASH_MOVE_TO_TARGET_DURATION - fadeDelay;
                        tween( uiOpacity )
                            .delay( fadeDelay )
                            .to( Math.max( 0, fadeDuration ), { opacity: 0 } )
                            .start();

                        Common.MoveTo(
                            effectNode,
                            dropWorldPos,
                            targetWorldPos,
                            FlyManager.ADD_CASH_MOVE_TO_TARGET_DURATION,
                            () => {
                                // 回收前重置透明度，避免下次取出是透明的
                                Tween.stopAllByTarget( uiOpacity );
                                uiOpacity.opacity = 255;
                                PrefabPoolManager.GetInstance().ReturnNode( poolKey, effectNode );
                                // cancelId 不符 → 演出已被取消（例：EnterFreeState 演出結束時 dispatch CANCEL_ADD_CASH_ANIMATION）
                                //   跳過 SetReelSymbolMode 與框關閉邏輯，避免污染下游 SetAllReelSymbolMode(Normal) 設定
                                if ( !this.node?.isValid || this.m_addCashCancelId !== cancelId ) return;
                                this.SetReelSymbolMode( col, ReelSymbolMode.CashAndBlank );
                                // 此列最後一個符號落底時才關閉投入框
                                if ( i === lastIndexPerCol.get( col ) && effectPlate )
                                {
                                    effectPlate.SetFreeGameAddCashFrameShow( col, false );
                                    const fData = colFrameDataMap.get( col );
                                    if ( fData ) { Common.PopNode( fData ); }
                                    colFrameDataMap.delete( col );
                                }
                            }
                        );
                    }
                    else
                    {
                        // 沒有 targetNode 也要確保回收前是正常透明度
                        const uiOpacity = effectNode.getComponent( UIOpacity );
                        if ( uiOpacity )
                        {
                            Tween.stopAllByTarget( uiOpacity );
                            uiOpacity.opacity = 255;
                        }
                        PrefabPoolManager.GetInstance().ReturnNode( poolKey, effectNode );
                    }
                } );
            } );
        }

        const totalDuration = ( playList.length - 1 ) * intervalSeconds + animDuration + FlyManager.ADD_CASH_MOVE_TO_TARGET_DURATION;
        await Define.Wait( this, totalDuration );
        // 安全清理：正常情況下框已在 MoveTo callback 中關閉；此處處理異常殘留
        for ( const [ remainCol, fData ] of colFrameDataMap )
        {
            if ( effectPlate ) { effectPlate.SetFreeGameAddCashFrameShow( remainCol, false ); }
            if ( fData ) { Common.PopNode( fData ); }
        }
        colFrameDataMap.clear();
        eventManager.Dispatch( BLACK_MASK_EVENT.HIDE_BLACK_MASK );

        try { callback?.(); } catch ( e ) { log( "[FlyManager] PlayAddCashAnimation callback error:", e ); }
    }

    /**
     * @ch 在節點底下依名稱尋找子節點（含孫節點）
     */
    private FindChildByName(root: Node, name: string): Node | null {
        if (!root || !root.isValid) return null;
        if (root.name === name) return root;
        for (let i = 0; i < root.children.length; i++) {
            const found = this.FindChildByName(root.children[i], name);
            if (found) return found;
        }
        return null;
    }

    /**
     * @ch 依起始世界座標判斷 Scatter→魔法罐 是否使用長軌（前三輪 Long，後三輪 Short）
     * @param startWorldPosition 起始世界座標
     * @returns 第 0–2 輪為 true（Long_Trail），第 3–5 輪為 false；無法對應盤面時預設 true
     */
    private IsScatterToMagicPotLongTrailByStartWorldPosition( startWorldPosition: Vec3 ): boolean
    {
        const slotReels = Common.m_gameView?.SlotReels;
        if ( !slotReels )
        {
            return true;
        }

        let nearestCol = 0;
        let smallestDx = Number.POSITIVE_INFINITY;
        for ( let col = 0; col < Game_Define.COL; ++col )
        {
            const refWorldPos = slotReels.GetSymbolInitWorldPositionFromColRow( col, 0 );
            const dx = Math.abs( startWorldPosition.x - refWorldPos.x );
            if ( dx < smallestDx )
            {
                smallestDx = dx;
                nearestCol = col;
            }
        }

        return nearestCol < 3;
    }

    /**
     * @ch 播放 Scatter 飛向魔法罐的 Trail 效果（結構同 PlayCollectTrailEffect）
     * @param startWorldPosition 起始世界座標
     * @param endWorldPosition 結束世界座標
     * @param callback 完成後回調
     */
    async PlayShowScatterToMagicPotAnimation(startWorldPosition: Vec3, endWorldPosition: Vec3, callback?: () => void): Promise<void>
    {
        let effectNode: Node = null;
        let scatterSpine: BaseSpine = null;
        effectNode = PrefabPoolManager.GetInstance().GetNode( FlyManager.SCATTER_TO_MAGIC_POT_POOL_KEY, this.node );
            if ( !effectNode )
            {
                log( "[FlyManager] PlayShowScatterToMagicPotAnimation 失敗: 無法建立飛行效果節點" );
                return;
            }
            effectNode.setWorldPosition( startWorldPosition );
            scatterSpine = effectNode.getComponent( BaseSpine );
            if ( !scatterSpine )
            {
                log( "[FlyManager] PlayShowScatterToMagicPotAnimation 失敗: 無法取得 BaseSpine 元件" );
                PrefabPoolManager.GetInstance().ReturnNode( FlyManager.SCATTER_TO_MAGIC_POT_POOL_KEY, effectNode );
                callback?.();
                return;
            }

            const isLong = this.IsScatterToMagicPotLongTrailByStartWorldPosition( startWorldPosition );

            scatterSpine.SetNodeActivity( true );
            const startBoneName = isLong ? "Long_Start_Control" : "Short_Start_Control";
            const endBoneName = isLong ? "Long_End_Control" : "Short_End_Control";
            const startBone = scatterSpine.Spine.findBone( startBoneName );
            const endBone = scatterSpine.Spine.findBone( endBoneName );

            if ( !startBone || !endBone )
            {
                log( `[FlyManager] PlayShowScatterToMagicPotAnimation 失敗: 無法找到 Spine Bone(${startBoneName}/${endBoneName})` );
                scatterSpine.SetNodeActivity( false );
                PrefabPoolManager.GetInstance().ReturnNode( FlyManager.SCATTER_TO_MAGIC_POT_POOL_KEY, effectNode );
                callback?.();
                return;
            }

            const spineNode = scatterSpine.Spine?.node ?? scatterSpine.node;

            const startLocalPos = getNodeSpaceAR( spineNode, startWorldPosition );
            const endLocalPos = getNodeSpaceAR( spineNode, endWorldPosition );

            const animName = isLong ? "Long_Trail_Up" : "Short_Trail_Up";

            scatterSpine.PlayAnimation( animName );
            endBone.x = endLocalPos.x;
            endBone.y = endLocalPos.y;
            startBone.x = startLocalPos.x;
            startBone.y = startLocalPos.y;

            await Define.Wait( this, 0.5 );

            scatterSpine.SetNodeActivity( false );
            if (effectNode) {
                PrefabPoolManager.GetInstance().ReturnNode( FlyManager.SCATTER_TO_MAGIC_POT_POOL_KEY, effectNode );
            }

            callback?.();
    }

    /**@ch 設定指定輪的符號顯示模式 */
    private SetReelSymbolMode(col: number, mode: ReelSymbolMode): void {
        Common.m_gameView?.SlotReels.SetReelSymbolMode( col, mode );
    }
    //#endregion 方法

    //#region 測試功能
    /**
     * @ch 註冊測試按鍵
     */
    private RegisterTestKeyCodes() {
        if (!DEBUG) return;
        input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
    }

    /**
     * @ch 取消註冊測試按鍵
     */
    private UnregisterTestKeyCodes() {
        if (!DEBUG) return;
        input.off(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
    }

    /**
     * @ch 檢查測試按鍵
     */
    private CheckTestKeyCode(event: EventKeyboard) {
        return;
        console.log("[FlyManager] CheckTestKeyCode", event.keyCode);
        switch (event.keyCode) {
            case KeyCode.DIGIT_0:
                // 測試：播放 flyToCollect 到第一列的演出
                this.TestPlayFlyToCollectToFirstColumn();
                break;

            case KeyCode.DIGIT_1:
                // 測試：投入 Cash Spine 演出（PlayAddCashAnimation）
                this.TestPlayAddCashAnimation();
                break;

            case KeyCode.DIGIT_2:
                // 測試：Scatter 飛向魔法罐（PlayShowScatterToMagicPotAnimation）
                this.TestPlayShowScatterToMagicPotAnimation();
                break;
        }
    }

    /**
     * @ch 測試：Scatter 飛向魔法罐（PlayShowScatterToMagicPotAnimation）
     * - 起終點座標可依場景調整
     */
    private TestPlayShowScatterToMagicPotAnimation(): void {
        const startWorldPos = new Vec3( 325.75, 73, 0 );
        const endWorldPos = new Vec3( 430, 115, 0 );

        this.PlayShowScatterToMagicPotAnimation(
            startWorldPos,
            endWorldPos,
            () => {
                log( "[FlyManager Test] Scatter 飛向魔法罐演出完成" );
            }
        );
    }

    /**
     * @ch 測試：投入 Cash Spine 演出（PlayAddCashAnimation）
     * - 依 m_addCashPositions 對應列索引 [0,1,2,3,4,5]，每列 50 個，間隔 0.05 秒
     */
    private TestPlayAddCashAnimation(): void {
        const countPerRound = 20;
        const columnsToDrop = [ 0, 1, 2, 3, 4, 5 ];
        const intervalSeconds = 0.1;

        this.PlayAddCashAnimation(
            countPerRound,
            columnsToDrop,
            intervalSeconds,
            () => {
                log( "[FlyManager Test] 投入 Cash 演出完成" );
            }
        );
    }

    /**
     * @ch 測試：播放 flyToCollect 到第一列（左側）的演出
     * - 起點模擬右側、終點為第一列（左側），可依場景調整座標
     */
    private TestPlayFlyToCollectToFirstColumn(): void {
        // 模擬從右側格子飛到第一列 collect 位置（左側）
        const startWorldPos = new Vec3(824, 580, 0);
        const endWorldPos = new Vec3(430, 115.75, 0);
        // 飛到第一列：source 在 4-6 列用 long，此處用 long 做測試
        const isLong = true;

        eventManager.Dispatch(
            FLY_EVENT.PLAY_FLY_TO_COLLECT_ANIMATION,
            this.m_collectNodePrefab,
            startWorldPos,
            endWorldPos,
            isLong,
            () => {
                console.log("[FlyManager Test] flyToCollect 到第一列演出完成");
            }
        );
    }
    //#endregion 測試功能
}

