110	    /**@ch 12 格 icon 的 SpriteChange（順序對應格 0~11）*/
111	    @property({ type: [SpriteChange], displayName: '12 格 icon SpriteChange' })
112	    private m_segmentSpriteChanges: SpriteChange[] = [];
