119	    @property({ type: [Node], displayName: '12 格落點演出節點' })
120	    private m_segmentNodes: Node[] = [];
121	
122	    /**@ch 飛行演出起點根節點 */
123	    @property({ type: Node, displayName: '飛行演出起點根節點' })
124	    private m_targetNode: Node = null;
125	
126	    /**
127	     * @ch BigWheel（EyeStrike2_BigWheel）BaseSpine：進場 Active / 落點 Collect / 退場 Out / 待機 Idle，skin 依落點功能切換。
128	     * 播放走 BaseSpine（內部 SpineKit，含動畫存在檢查 + setSlotsToSetupPose）。拖 FeatureWheelResult 節點（其上有 BaseSpine）。
129	     * Collect 取代結果展示牌（m_result* 已停用，僅保留屬性避免 prefab 反序列化警告）。
130	     */
131	    @property({ type: BaseSpine, displayName: 'BigWheel BaseSpine' })
132	    private m_bigWheelSpine: BaseSpine = null;
133	
134	    /**@ch 轉動方向：勾選=順時針，取消=逆時針（預設順時針）*/
135	    @property({ displayName: '順時針轉動' })
136	    private m_clockwise: boolean = true;
137	
138	    /**@ch Idle 緩轉一圈秒數（越大越慢；≤0 視為不緩轉）；方向跟隨「順時針轉動」*/
139	    @property({ displayName: 'Idle 一圈秒數' })
140	    private m_idleSecondsPerRev: number = 60;
141	    //#endregion 屬性
142	
143	    //#region 常數
144	    /**@ch 轉動時間（秒）；拉長以降低峰值角速度，減輕 12 格重複圖樣的車輪錯覺（視覺反向）*/
145	    private static readonly ROTATE_TIME = 3;//2.5;
146	    //#endregion 常數
147	
148	    //#region 變數
149	    /**@ch 遊戲視窗*/
150	    private m_gameView: GameView = null;
151	    /**@ch 是否初始化*/
152	    private m_isInit = false;
153	    /**@ch 是否轉動中（轉動中/閒置兩互斥態）*/
154	    private m_isSpinning = false;
155	    /**@ch 是否處於 Idle 緩轉態（SHOW_UI/RESUME_IDLE 開、HIDE_UI/PlaySpin 關；轉動中由 m_isSpinning 暫停，轉完不自動恢復）*/
156	    private m_isIdle = false;
157	    /**@ch 是否已註冊事件*/
158	    private m_isEventRegistered = false;
159	    /**@ch 當前 12 格資料*/
160	    private m_segments: SegmentDescriptor[] = [];
161	
162	    /**@ch 事件列表*/
163	    private readonly EVENT_LIST: string[] = [
164	        FEATURE_WHEEL_EVENT.INIT,
165	        FEATURE_WHEEL_EVENT.SET_WHEEL_DATA,
166	        FEATURE_WHEEL_EVENT.PLAY_SPIN,
167	        FEATURE_WHEEL_EVENT.SHOW_UI,
168	        FEATURE_WHEEL_EVENT.HIDE_UI,
169	        FEATURE_WHEEL_EVENT.PLAY_ENTER,
170	        FEATURE_WHEEL_EVENT.PLAY_EXIT,
171	        FEATURE_WHEEL_EVENT.RESUME_IDLE,
172	        FEATURE_WHEEL_EVENT.HIDE_RESULT,
173	        FEATURE_WHEEL_EVENT.GET_TARGET_NODE,
174	    ];
175	    //#endregion 變數
176	
177	    //#region 生命週期
178	    onLoad() {
179	        this.RegisterEvent();
180	        this.DevAssertConfig();
181	        this.RegisterTestKeyCodes();
182	    }
183	
184	    onDestroy() {
