189	    /**
190	     * @ch 每幀 Idle 緩轉：僅在 Idle 態且非轉動中執行（兩旋轉路徑互斥，不同幀寫 m_wheelNode）
191	     * 方向跟隨 m_clockwise（順時針 = z 遞減，與 ComputeTargetAngle 一致）
192	     */
193	    update(dt: number) {
194	        if (!this.m_isIdle || this.m_isSpinning) {
195	            return;
196	        }
197	        if (this.m_idleSecondsPerRev <= 0) {
198	            return;
199	        }
200	        if (!this.m_wheelNode || !this.m_wheelNode.isValid) {
201	            return;
202	        }
203	        const dir = this.m_clockwise ? -1 : 1;
204	        const deltaAngle = dir * (360 / this.m_idleSecondsPerRev) * dt;
205	        // 正規化防 BC-8 連續累積漂移（與 RotateToIndex 收尾一致），spin 起點讀 currentAngle 仍正確
206	        const next = NormalizeAngle(this.m_wheelNode.eulerAngles.z + deltaAngle);
