215	        }
216	        this.m_isEventRegistered = true;
217	        this.EVENT_LIST.forEach(event => eventManager.Register(event, this));
218	    }
219	
220	    private UnregisterEvent() {
221	        if (!this.m_isEventRegistered) {
222	            return;
223	        }
224	        this.EVENT_LIST.forEach(event => eventManager.UnRegister(event, this));
225	        this.m_isEventRegistered = false;
226	    }
