243	                    this.SetWheelData(args[0]);
244	                } else {
245	                    error('FeatureWheel SET_WHEEL_DATA 參數無效');
246	                }
247	                break;
248	
249	            case FEATURE_WHEEL_EVENT.PLAY_SPIN:
250	                if (args.length > 0 && typeof args[0] === 'number') {
251	                    this.PlaySpin(args[0], typeof args[1] === 'function' ? args[1] : undefined);
252	                } else {
253	                    error('FeatureWheel PLAY_SPIN 參數無效');
254	                }
255	                break;
256	
257	            case FEATURE_WHEEL_EVENT.SHOW_UI:
258	                this.SetUIShow(true);
259	                break;
260	
261	            case FEATURE_WHEEL_EVENT.HIDE_UI:
262	                this.SetUIShow(false);
263	                break;
264	
265	            case FEATURE_WHEEL_EVENT.PLAY_ENTER:
266	                this.PlayEnter(typeof args[0] === 'function' ? args[0] : undefined);
267	                break;
268	
269	            case FEATURE_WHEEL_EVENT.PLAY_EXIT:
270	                this.PlayExit(typeof args[0] === 'function' ? args[0] : undefined);
271	                break;
272	
273	            case FEATURE_WHEEL_EVENT.RESUME_IDLE:
274	                this.ResumeIdle();
275	                break;
276	
277	            case FEATURE_WHEEL_EVENT.HIDE_RESULT:
278	                this.HideResult();
279	                break;
280	
281	            case FEATURE_WHEEL_EVENT.GET_TARGET_NODE:
282	                if (typeof args[0] === 'function') {
283	                    args[0](this.GetTargetNode());
284	                } else {
285	                    error('FeatureWheel GET_TARGET_NODE 缺少 callback');
286	                }
287	                break;
288	        }
289	    }
