301	    /**
302	     * @ch 初始化（IF-1）
303	     */
304	    private Init(gameView: GameView) {
305	        this.m_gameView = gameView;
306	        this.m_isInit = true;
307	    }
308	
309	    /**
310	     * @ch 設置 12 格資料並更新 icon（IF-2 / BC-5 / EH-2）
311	     * @param segments server 給的 12 格資料
312	     */
313	    private SetWheelData(segments: SegmentDescriptor[]) {
314	        // BC-9 行為約束：轉動中拒絕換資料，避免落點與顯示不一致
315	        if (this.m_isSpinning) {
316	            warn('FeatureWheel SetWheelData 轉動中，拒絕本次設置');
317	            return;
318	        }
319	        if (!segments) {
320	            warn('FeatureWheel SetWheelData 資料為空');
321	            return;
322	        }
323	
324	        // EH-2：長度 > 12 取前 12
325	        if (segments.length > FEATURE_WHEEL_SEGMENT_COUNT) {
326	            warn(`FeatureWheel SetWheelData 長度 ${segments.length} > ${FEATURE_WHEEL_SEGMENT_COUNT}，取前 ${FEATURE_WHEEL_SEGMENT_COUNT} 格`);
327	        }
328	        this.m_segments = segments.slice(0, FEATURE_WHEEL_SEGMENT_COUNT);
329	
330	        // EH-2：長度 < 12 → 渲染已提供格，其餘格保持預設
331	        if (this.m_segments.length < FEATURE_WHEEL_SEGMENT_COUNT) {
332	            warn(`FeatureWheel SetWheelData 長度 ${this.m_segments.length} < ${FEATURE_WHEEL_SEGMENT_COUNT}，其餘格保持預設`);
333	        }
334	
335	        this.BindSegmentIcons();
336	
337	        this.m_isIdle = true;
338	
339	        // 待機隱藏 BigWheel Spine（feature 專屬元件，Active 進場才顯示）；軟體 12 格慢轉由 m_isIdle 驅動、照舊
340	        this.SetBigWheelSpineVisible(false);
341	    }
342	
343	    /**
344	     * @ch 依當前資料綁定各格 icon（BC-4 / EH-2）
345	     * None / 無資料格 → 清空不顯示；其餘依 type 換圖。倍率值已移除，Label 一律清空防殘留。
346	     * FS_BG 底圖：僅該格 type 為 FreeGame 時開啟（作底凸顯免費遊戲符號）；其餘格關閉以保冪等（R-2）。
347	     */
348	    private BindSegmentIcons() {
349	        // 迭代固定 12 格確保冪等（R-2）：二次設定變少時，超出資料的格重置為預設，不殘留舊值
350	        for (let i = 0; i < FEATURE_WHEEL_SEGMENT_COUNT; i++) {
351	            const seg = i < this.m_segments.length ? this.m_segments[i] : null;
352	
353	            // 換 icon：None / 無資料格 → 清空（暫不顯示）；其餘依 type 換圖（BC-4）
354	            const spriteChange = this.m_segmentSpriteChanges[i];
355	            if (spriteChange) {
356	                if (!seg || seg.type === FeatureWheelSegmentType.None) {
357	                    spriteChange.ClearSprite();
358	                } else {
359	                    spriteChange.ChangeSpriteByIndex(TypeToIconIndex(seg.type));
360	                }
361	
362	                // FS_BG 底圖：與 icon 同生命週期，從同格 item root 取子節點（無資料/非 FreeGame 一律關，保冪等）
363	                const fsBg = spriteChange.node?.getChildByName('FS_BG');
364	                if (fsBg) {
365	                    fsBg.active = !!seg && seg.type === FeatureWheelSegmentType.FreeGame;
366	                }
367	            }
368	
369	            // 倍率值已移除：清空 Label，避免殘留設計期/前一次的文字
370	            const label = this.m_segmentValueLabels[i];
371	            if (label) {
372	                label.string = '';
373	            }
374	        }
375	    }
376	
377	    /**
378	     * @ch 轉動並落在指定格（IF-3 / BC-3 / BC-6 / BC-7 / BC-8 / BC-9 / EH-1 / EH-3）
379	     * 守衛順序（DR-10）：① 轉動中重入 → ② 未初始化/無資料 → ③ landIndex 範圍
380	     * 完成訊號鏈（DR-2 / BC-7）：await 轉動 → await 落點演出 → callback → 最後釋放 m_isSpinning
381	     * @param landIndex 落點格索引 (0~11)
382	     * @param callback 完成回調，帶選中格 {index, type, value}
383	     */
384	    private async PlaySpin(landIndex: number, callback?: (result: SpinResult) => void) {
385	        // ① BC-9 轉動中重入 → 忽略
386	        if (this.m_isSpinning) {
387	            warn('FeatureWheel PlaySpin 轉動中，忽略本次請求');
388	            return;
389	        }
390	        // ② EH-3 未初始化或無資料
391	        if (!this.m_isInit || this.m_segments.length === 0) {
392	            warn('FeatureWheel PlaySpin 未初始化或尚未設置輪盤資料');
393	            return;
394	        }
395	        // ③ EH-1 landIndex 範圍
396	        if (landIndex < 0 || landIndex >= FEATURE_WHEEL_SEGMENT_COUNT) {
397	            warn(`FeatureWheel PlaySpin landIndex ${landIndex} 超出範圍 0~${FEATURE_WHEEL_SEGMENT_COUNT - 1}`);
398	            return;
399	        }
400	
401	        this.m_isSpinning = true;
402	        // 轉動開始即關閉 Idle：轉完「不」自動恢復；待盤面其他表演結束由 RESUME_IDLE 手動恢復
403	        this.m_isIdle = false;
404	        // 快轉視覺：先重設 default skin（多次轉動避免殘留上一次落點功能圖），再播正常速 Idle 循環（轉動中的動畫）；
405	        // 停下時 PlayLandAnnounce 的 Collect 以 clearTrack(0) 自然蓋掉本 Idle。
406	        this.SetSpineSkin(BIG_WHEEL_DEFAULT_SKIN);
407	        this.PlaySpineLoop(BIG_WHEEL_ANIM.Idle);
408	        try {
409	            await this.RotateToIndex(landIndex);     // BC-3 / BC-6
410	            await this.PlayLandAnnounce(landIndex);  // BC-7
411	            const seg = this.m_segments[landIndex];
412	            // callback 包獨立 try（R-1）：呼叫端 callback 自身例外不被遮蔽成「轉動失敗」
413	            try {
414	                callback?.({ index: landIndex, type: seg.type });
415	            } catch (cbErr) {
416	                error('FeatureWheel PlaySpin callback 執行失敗: ' + cbErr);
417	            }
418	        } catch (e) {
419	            error('FeatureWheel PlaySpin 轉動/演出失敗: ' + e);
420	        } finally {
421	            // BC-7：釋放點在 callback 之後，避免演出/回呼期間被重入
422	            this.m_isSpinning = false;
423	        }
424	    }
425	
426	    /**
427	     * @ch 旋轉到 landIndex，停在頂端指針（BC-3 / BC-6）
428	     * 角度計算用 ComputeTargetAngle（依 m_clockwise 單向單調，不沿用會反向的 angleDiff）
429	     */
430	    private RotateToIndex(landIndex: number): Promise<void> {
431	        return new Promise<void>((resolve) => {
432	            if (!this.m_wheelNode || !this.m_wheelNode.isValid) {
433	                resolve();
434	                return;
435	            }
436	            const currentAngle = this.m_wheelNode.eulerAngles.z;
437	            const targetAngle = ComputeTargetAngle(landIndex, currentAngle, this.m_clockwise);
438	            const anim = { angle: currentAngle };
439	            tween(anim)
440	                .to(FeatureWheelManager.ROTATE_TIME, { angle: targetAngle }, {
441	                    easing: 'cubicOut',
442	                    onUpdate: () => {
443	                        if (this.m_wheelNode?.isValid) {
444	                            this.m_wheelNode.setRotationFromEuler(0, 0, anim.angle);
445	                        }
446	                    },
447	                })
448	                .call(() => {
449	                    // DR-9：轉動結束後正規化角度，防 BC-8 連續轉動累積漂移
450	                    if (this.m_wheelNode?.isValid) {
451	                        this.m_wheelNode.setRotationFromEuler(0, 0, NormalizeAngle(targetAngle));
452	                    }
453	                    resolve();
454	                })
455	                .start();
456	        });
457	    }
