459	    /**
460	     * @ch 落點演出（BC-7）：BigWheel Spine 取代結果展示牌——依落點 type 切 skin，播 Collect「中間功能亮起」，await 播畢才 resolve。
461	     * 時序：呼叫端在 RotateToIndex（轉輪停下）後呼叫，符合「轉輪停下來後中間功能亮起」。
462	     * Collect 播畢後中間維持亮起（end pose），退場由 PlayExit 的 Out（盤面回歸+暗掉）負責。
463	     * Spine 缺失（m_bigWheelSpine 未綁）→ PlaySpineOnce 立即 resolve，不 hang 呼叫端。
464	     */
465	    private async PlayLandAnnounce(landIndex: number): Promise<void> {
466	        const seg = this.m_segments[landIndex];
467	        if (!seg) {
468	            return;
469	        }
470	        // 先切到落點功能 skin（Multiplier/Upgrade/Shift 直對；FG/Grand/None → default），再播 Collect
471	        this.SetSpineSkin(TypeToSkin(seg.type));
472	        await this.PlaySpineOnce(BIG_WHEEL_ANIM.Collect);
473	    }
474	
475	    /**
476	     * @ch [已停用] 套用落點 type 對應圖到結果展示牌 SpriteChange。
477	     * ⚠️ Collect 動畫取代結果展示牌後無呼叫者；保留待美術定案後連同 m_result* 屬性整條移除。
478	     */
479	    private ApplyResultSprite(spriteChange: SpriteChange | null, type: FeatureWheelSegmentType) {
480	        if (!spriteChange) {
481	            return;
482	        }
483	        if (type === FeatureWheelSegmentType.None) {
484	            spriteChange.ClearSprite();
485	        } else {
486	            spriteChange.ChangeSpriteByIndex(TypeToIconIndex(type));
487	        }
488	    }
