515	    /**
516	     * @ch 手動恢復 Idle 緩轉（IF）+ 隱藏 BigWheel Spine（回待機）
517	     * 用途：PlaySpin 後輪盤停住，呼叫端在盤面其他表演結束後觸發此方法才續轉
518	     * 注意：若仍在轉動中，由 update 的 m_isSpinning 守衛延後至轉完才實際緩轉
519	     * Spine：待機隱藏 BigWheel（feature 專屬元件，Active 進場才顯示）；軟體 12 格緩轉與 Spine 為兩獨立層，慢轉照舊
520	     */
521	    private ResumeIdle() {
522	        this.m_isIdle = true;
523	        this.SetBigWheelSpineVisible(false);
524	    }
