537	    /**
538	     * @ch 播放進場 Active（一個 round 一次，落在第一次轉動前）；播畢回調。
539	     * 進場用 default skin（中間尚未落定功能）。Spine 缺失 → PlaySpineOnce 立即 resolve，不 hang 呼叫端。
540	     * 先顯示 BigWheel Spine（待機時隱藏），否則整段 feature 演出看不到。
541	     * @param onDone 動畫播畢回調
542	     */
543	    private async PlayEnter(onDone?: () => void) {
