579	    /**
580	     * @ch 播放 BigWheel 單次（非循環）動畫，await 播畢/中斷才 resolve。委派 SpineKit（經 BaseSpine.PlayAnimation）。
581	     * Spine 缺失 → 立即 resolve；動畫名無效 → BaseSpine 內部 warn + 回 false，皆不 hang 呼叫端（DR-2 完成訊號鏈防 hang）。
582	     * @param animName 動畫名（Active/Collect/Out）
583	     */
584	    private async PlaySpineOnce(animName: string): Promise<void> {
585	        if (!this.m_bigWheelSpine || !this.m_bigWheelSpine.isValid) {
586	            return;
587	        }
588	        // BaseSpine.PlayAnimation 回 Promise<boolean>（播畢/中斷時 resolve）；此處只需等其結束，忽略結果旗標
589	        await this.m_bigWheelSpine.PlayAnimation(animName, undefined, false);
590	    }
