592	    /**
593	     * @ch 播放 BigWheel 循環動畫（快轉 Idle），不 await（循環動畫不等完成）。委派 SpineKit（經 BaseSpine.PlayAnimation）。
594	     * @param animName 動畫名（Idle）
595	     */
596	    private PlaySpineLoop(animName: string) {
597	        if (!this.m_bigWheelSpine || !this.m_bigWheelSpine.isValid) {
598	            return;
599	        }
600	        // 循環播放：isLoop=true；回傳 Promise 於首圈完成 resolve，不 await（不影響續循環）
601	        this.m_bigWheelSpine.PlayAnimation(animName, undefined, true);
602	    }
