646	    /**
647	     * @ch 檢查測試按鍵，走真實 eventManager 事件路徑驗證 FeatureWheel 功能
648	     * DIGIT_1：初始化 + 設定預設輪盤資料 + 顯示 UI（一鍵就緒）
649	     * DIGIT_2：轉動到下一格（循環 0~11）並印出落點結果（驗證旋轉/落點演出/callback）
650	     * DIGIT_3：重設隨機輪盤資料（驗證 icon 與乘倍數值動態更新）
651	     * DIGIT_4：切換顯示/隱藏 UI
652	     */
653	    private CheckTestKeyCode(event: EventKeyboard) {
654	        switch (event.keyCode) {
655	            // case KeyCode.DIGIT_1:
656	            //     log('[FeatureWheel 測試] 初始化 + 設定預設資料 + 顯示 UI');
657	            //     // INIT 僅需非 null 物件以通過參數驗證並翻起 m_isInit；
658	            //     // m_gameView 在本元件未被讀取，測試以 this.node 佔位即可
659	            //     eventManager.Dispatch(FEATURE_WHEEL_EVENT.INIT, this.node);
660	            //     eventManager.Dispatch(FEATURE_WHEEL_EVENT.SET_WHEEL_DATA, GetDefaultSegments());
661	            //     eventManager.Dispatch(FEATURE_WHEEL_EVENT.SHOW_UI);
662	            //     break;
663	
664	            case KeyCode.DIGIT_2: {
665	                const landIndex = this.m_testLandIndex % FEATURE_WHEEL_SEGMENT_COUNT;
666	                this.m_testLandIndex++;
667	                log(`[FeatureWheel 測試] 轉動到第 ${landIndex} 格`);
668	                eventManager.Dispatch(FEATURE_WHEEL_EVENT.PLAY_SPIN, landIndex, (result: SpinResult) => {
669	                    log(`[FeatureWheel 測試] 落點結果 index=${result.index} type=${result.type}`);
670	                });
671	                break;
672	            }
673	            
674	            case KeyCode.DIGIT_3:
675	                log('[FeatureWheel 測試] 恢復 Idle 緩轉');
676	                eventManager.Dispatch(FEATURE_WHEEL_EVENT.HIDE_RESULT);
677	                eventManager.Dispatch( FEATURE_WHEEL_EVENT.RESUME_IDLE );
678	                break;
679	
680	            case KeyCode.DIGIT_4:
681	                this.m_testUIShown = !this.m_testUIShown;
682	                log(`[FeatureWheel 測試] 切換 UI 顯示 → ${this.m_testUIShown}`);
683	                eventManager.Dispatch(this.m_testUIShown ? FEATURE_WHEEL_EVENT.SHOW_UI : FEATURE_WHEEL_EVENT.HIDE_UI);
684	                break;
685	        }
686	    }
687	
688	    /**
689	     * @ch 產生 12 格隨機測試資料（type 隨機）
690	     */
691	    private BuildRandomTestSegments(): SegmentDescriptor[] {
692	        const types = [
693	            FeatureWheelSegmentType.SymbolConvert,
694	            FeatureWheelSegmentType.Multiplier,
695	            FeatureWheelSegmentType.Upgrade,
696	            FeatureWheelSegmentType.GrandJP,
697	            FeatureWheelSegmentType.FreeGame,
698	        ];
699	        const segments: SegmentDescriptor[] = [];
700	        for (let i = 0; i < FEATURE_WHEEL_SEGMENT_COUNT; i++) {
701	            const type = types[Math.floor(Math.random() * types.length)];
702	            segments.push({ type });
703	        }
704	        return segments;
705	    }
706	    //#endregion 測試功能
