export function IsKnownSegmentType(type: number): boolean {
    return TYPE_ICON_CONFIG[type as FeatureWheelSegmentType] !== undefined;
}

/** @ch BigWheel Spine 預設 skin 名（對齊 EyeStrike2_BigWheel skins：default/Multiplier/Shift/Upgrade） */
export const BIG_WHEEL_DEFAULT_SKIN = 'default';

/**
 * @ch type → BigWheel Spine skin 名對照（Collect/Out 中間功能亮起/暗掉用）
 * skin 語意 = 轉輪落在哪個功能、中間那格亮起；Active(進場) / Idle(待機) 一律用 default。
 * SymbolConvert 對應 Spine skin「Shift」（與 EyeStrike2_BigWheel skins 對齊）。
 * FreeGame / GrandJP 無中間功能 skin（走各自 FG 交棒 / JP 報獎流程），未列入 → 回 default。
 */
export const TYPE_SKIN_CONFIG: Readonly<Partial<Record<FeatureWheelSegmentType, string>>> = {
    [FeatureWheelSegmentType.Multiplier]: 'Multiplier',
    [FeatureWheelSegmentType.Upgrade]: 'Upgrade',
    [FeatureWheelSegmentType.SymbolConvert]: 'Shift',
};

/**
 * @ch type → BigWheel Spine skin 名（未列入的 type，含 FreeGame/GrandJP/None → 回 default）
 * @param type 功能類型
 */
export function TypeToSkin(type: FeatureWheelSegmentType): string {
    return TYPE_SKIN_CONFIG[type] ?? BIG_WHEEL_DEFAULT_SKIN;
}

