/**
 * @ch 播放飛行效果
 * @param data 飛行效果資料
 */
private async PlayFlyEffect( data: ar2es2Proto.IFeatureResult )
{
    log( "PlayFlyEffect data: " + JSON.stringify( data ) );

    // ⚠️ 暫代演出：尚無專屬「功能飛向盤面」Spine，先借用 Scatter→MagicPot 飛行動畫頂著。
    //    待正式資源就緒，改 dispatch 對應的功能飛行事件即可（起終點取法不變）。
    const positions = data.Positions ?? [];
    if ( positions.length === 0 )
    {
        return; // 無落點位置 → 無暫代飛行可播
    }

    // 起點：向 FeatureWheelManager 取目標節點（同步 dispatch；callback 立即回傳節點）
    let startNode: Node = null;
    eventManager.Dispatch( FEATURE_WHEEL_EVENT.GET_TARGET_NODE, ( node: Node ) => { startNode = node; } );
    if ( startNode == null || !startNode.isValid )
    {
        console.warn( "[FeatureWheelShowState] PlayFlyEffect 取不到目標節點，跳過暫代飛行" );
        return;
    }
    const startWorldPos = startNode.getWorldPosition();

    // 終點：每個 Position 對應的盤面符號世界座標；各位置平行飛、全部播畢才續流程。
    // 註：暫代借用的 PLAY_SHOW_SCATTER_TO_MAGIC_POT_ANIMATION 在「建立節點失敗」分支不回 callback，
    //    與 ScatterShowState 既有用法同源風險（無 timeout），暫代階段可接受。
    await Promise.all( positions.map( pos =>
    {
        const endWorldPos = this.m_gameView.SlotReels.GetSymbolInitWorldPositionFromPosition( pos );
        return new Promise<void>( resolve =>
        {
            eventManager.Dispatch( FLY_EVENT.PLAY_SHOW_SCATTER_TO_MAGIC_POT_ANIMATION, startWorldPos, endWorldPos, () => resolve() );
        } );
    } ) );

    await Define.Wait( this.m_gameView, 0.2 );
}

