 * 依據 Game_Define.ROW_CONFIG 進行伺服器位置解碼
 * @param data 伺服器位置編碼
 * @returns { col, row } 或 null(超出範圍)
 */
static DecodeServerPosByRowConfig( data: number ): { col: number; row: number } | null
{
	if ( data === undefined || data === null || data < 0 )
	{
		return null;
	}

	let acc = 0;
	for ( let col = 0; col < Game_Define.COL; ++col )
	{
		const height = Game_Define.ROW_CONFIG[ col ] || 0;
		if ( data < acc + height )
		{
			const row = data - acc;
			return { col, row };
		}
		acc += height;
	}
	return null;
}

