//#endregion 方法

//#region 測試功能
/**
 * @ch 註冊測試按鍵
 */
private RegisterTestKeyCodes() {
    if (!DEBUG) return;
    input.on(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
}

/**
 * @ch 取消註冊測試按鍵
 */
private UnregisterTestKeyCodes() {
    if (!DEBUG) return;
    input.off(Input.EventType.KEY_DOWN, this.CheckTestKeyCode, this);
}

/**
 * @ch 檢查測試按鍵
 */
private CheckTestKeyCode(event: EventKeyboard) {
    return;
    console.log("[FlyManager] CheckTestKeyCode", event.keyCode);
    switch (event.keyCode) {
        case KeyCode.DIGIT_0:
            // 測試：播放 flyToCollect 到第一列的演出
            this.TestPlayFlyToCollectToFirstColumn();
            break;

        case KeyCode.DIGIT_1:
            // 測試：投入 Cash Spine 演出（PlayAddCashAnimation）
            this.TestPlayAddCashAnimation();
            break;

        case KeyCode.DIGIT_2:
            // 測試：Scatter 飛向魔法罐（PlayShowScatterToMagicPotAnimation）
            this.TestPlayShowScatterToMagicPotAnimation();
            break;
    }
}

/**
 * @ch 測試：Scatter 飛向魔法罐（PlayShowScatterToMagicPotAnimation）
 * - 起終點座標可依場景調整
 */
private TestPlayShowScatterToMagicPotAnimation(): void {
    const startWorldPos = new Vec3( 325.75, 73, 0 );
    const endWorldPos = new Vec3( 430, 115, 0 );

    this.PlayShowScatterToMagicPotAnimation(
