//#region FeatureWheel Trail 位置測試
/**
 * @ch 測試用 Trail 起點世界座標（fallback；理應對齊 FeatureWheel 飛行起點根節點中心，依場景調整）。
 * 註：刻意不在 FlyManager import FeatureWheel 取真實起點（維持解耦），故測試用此固定起點。
 */
private static readonly TEST_TRAIL_START_WORLD_POS = new Vec3( 0, 150, 0 );

/**@ch 測試用：Trail 落點 column 游標（DIGIT_3 每次 +1，0~COL-1 循環）*/
private m_testTrailCol: number = 0;

/**@ch 測試用：Trail 落點 row 游標（DIGIT_4 每次 +1，於 col 0 欄內循環）*/
private m_testTrailRow: number = 0;

/**
 * @ch 測試核心：FeatureWheel Trail 飛向盤面 (col,row)。
 * 終點取「真實盤面格世界座標」（這是要驗證的飛行目標）；起點用可調 fallback 常數。
 * 位置怪時：先看 log 的 start/end 是否如預期，再判斷是起點、終點或 bone 換算的問題。
 * @param col 盤面 column（0~5；決定 L/R）
 * @param row 盤面 row
 * @param skinName Skin（預設 Multiplier，較明顯）
 */
private TestPlayFeatureWheelTrailAt( col: number, row: number, skinName: string = "Multiplier" ): void {
    const slotReels = Common.m_gameView?.SlotReels;
    if ( !slotReels )
    {
        log( "[FlyManager Test] 無 SlotReels，無法取得盤面座標" );
        return;
    }

    const startWorldPos = FlyManager.TEST_TRAIL_START_WORLD_POS.clone();
    const endWorldPos = slotReels.GetSymbolInitWorldPositionFromColRow( col, row );
    const side = col < FlyManager.FEATURE_TRAIL_LR_SPLIT ? "L(左)" : "R(右)";

    log( `[FlyManager Test] Trail → col=${col} row=${row} side=${side} skin=${skinName} ` +
         `start=(${startWorldPos.x.toFixed( 1 )},${startWorldPos.y.toFixed( 1 )}) ` +
         `end=(${endWorldPos.x.toFixed( 1 )},${endWorldPos.y.toFixed( 1 )})` );

    eventManager.Dispatch(
        FLY_EVENT.PLAY_FEATURE_WHEEL_TRAIL_ANIMATION,
        col,
        startWorldPos,
        endWorldPos,
        skinName,
        () => log( `[FlyManager Test] Trail col=${col} row=${row} 演出完成` )
    );
}

/**
 * @ch 測試：逐欄循環 Trail（row 0）。每按一次 DIGIT_3 飛向下一欄（0→1→…→5→0），
 * 用來檢查 6 欄終點位置與 L/R 切換（col<3 左、>=3 右）。
 */
private TestTrailCycleColumns(): void {
    const col = this.m_testTrailCol % Game_Define.COL;
    this.m_testTrailCol = ( this.m_testTrailCol + 1 ) % Game_Define.COL;
    this.TestPlayFeatureWheelTrailAt( col, 0 );
}

/**
 * @ch 測試：固定欄（col 0）逐列循環 Trail。每按一次 DIGIT_4 飛向該欄的下一列，
 * 用來檢查同一欄不同 row 的垂直終點位置。
 */
private TestTrailCycleRows(): void {
    const col = 0;
    const height = Game_Define.ROW_CONFIG[ col ] || 1;
    const row = this.m_testTrailRow % height;
    this.m_testTrailRow = ( this.m_testTrailRow + 1 ) % height;
    this.TestPlayFeatureWheelTrailAt( col, row );
}
